const { task, subtasks } = $json;
if (!Array.isArray(subtasks) || subtasks.length === 0) {
  return { error: 'subtasks array required', task };
}
return {
  task,
  subtasks: subtasks.map((s, i) => ({
    id: `subtask-${i + 1}`,
    description: s,
    worker: i % 2 === 0 ? 'worker-a' : 'worker-b',
    status: 'pending'
  }))
};

const subtasks = $json.subtasks || [];
for (const s of subtasks) { s.status = 'running'; }
return { ...$json, subtasks };

const subtask = $json;
const results = {
  'worker-a': 'Worker A completed: analysis done',
  'worker-b': 'Worker B completed: implementation done'
};
return {
  ...subtask,
  status: 'complete',
  result: results[subtask.worker] || `Worker processed: ${subtask.description}`,
  completed_at: new Date().toISOString()
};

const outputs = $input.all();
const completed = outputs.filter(o => o.status === 'complete');
return {
  task: $json.task,
  total_subtasks: outputs.length,
  completed: completed.length,
  results: outputs,
  all_done: completed.length === outputs.length,
  summary: `Completed ${completed.length}/${outputs.length} subtasks`
};
